actions.script:
import java.sql.Timestamp
Timestamp effectiveLogDate = logDate ?: ec.user.nowTimestamp Calendar cal = ec.user.getCalendarSafe() cal.setTimeInMillis(effectiveLogDate.time) cal.set(Calendar.MINUTE, 0) cal.set(Calendar.SECOND, 0) cal.set(Calendar.MILLISECOND, 0) Timestamp binStartDateTime = new Timestamp(cal.timeInMillis) cal.add(Calendar.HOUR_OF_DAY, 1) Timestamp binEndDateTime = new Timestamp(cal.timeInMillis)
Closure<String> norm = { Object value -> String text = value != null ? value.toString().trim() : '' return text ? text : '_' } String binKey = [ norm(toolName), norm(documentKind), norm(area), norm(subArea), norm(domainObject), norm(actionKind), norm(operationEffect), norm(executionChannel), norm(serviceName), norm(searchMode), norm(indexName) ].join('|')
def binValue = ec.entity.find('moqui.agent.AgentToolExecutionBin') .condition('binStartDateTime', binStartDateTime) .condition('binKey', binKey) .forUpdate(true) .one() boolean exists = binValue != null if (binValue) binValue = binValue.cloneValue() if (!binValue) { binValue = ec.entity.makeValue('moqui.agent.AgentToolExecutionBin') binValue.setSequencedIdPrimary() agentToolExecutionBinId = binValue.agentToolExecutionBinId binValue.binKey = binKey binValue.binStartDateTime = binStartDateTime binValue.binEndDateTime = binEndDateTime binValue.toolName = toolName binValue.documentKind = documentKind binValue.area = area binValue.subArea = subArea binValue.domainObject = domainObject binValue.actionKind = actionKind binValue.operationEffect = operationEffect binValue.executionChannel = executionChannel binValue.serviceName = serviceName binValue.searchMode = searchMode binValue.indexName = indexName binValue.executionCount = 0 binValue.successCount = 0 binValue.errorCount = 0 binValue.deniedCount = 0 binValue.confirmationRequiredCount = 0 binValue.hybridLlmRerankCount = 0 binValue.rerankerFallbackCount = 0 binValue.totalTimeMillis = 0 binValue.totalSquaredTime = 0 } else { agentToolExecutionBinId = binValue.agentToolExecutionBinId }
BigDecimal rt = (runningTimeMillis ?: 0) as BigDecimal binValue.executionCount = (binValue.executionCount ?: 0) + 1 if (Boolean.TRUE.equals(success) || success == 'Y') { binValue.successCount = (binValue.successCount ?: 0) + 1 } else { binValue.errorCount = (binValue.errorCount ?: 0) + 1 } if ((resultStatus ?: '') == 'denied') binValue.deniedCount = (binValue.deniedCount ?: 0) + 1 if ((confirmed == 'N' || Boolean.FALSE.equals(confirmed)) && riskLevelEnumId) { binValue.confirmationRequiredCount = (binValue.confirmationRequiredCount ?: 0) + 1 } if ((searchMode ?: '') == 'hybrid_llm_rerank') { binValue.hybridLlmRerankCount = (binValue.hybridLlmRerankCount ?: 0) + 1 } if (rerankerFallbackUsed == 'Y' || Boolean.TRUE.equals(rerankerFallbackUsed)) { binValue.rerankerFallbackCount = (binValue.rerankerFallbackCount ?: 0) + 1 }
binValue.totalTimeMillis = (binValue.totalTimeMillis ?: 0) + rt binValue.totalSquaredTime = (binValue.totalSquaredTime ?: 0) + (rt * rt) if (binValue.minTimeMillis == null || rt < (binValue.minTimeMillis as BigDecimal)) binValue.minTimeMillis = rt if (binValue.maxTimeMillis == null || rt > (binValue.maxTimeMillis as BigDecimal)) binValue.maxTimeMillis = rt binValue.lastLogDate = effectiveLogDate
if (exists) binValue.update() else binValue.create()
